module top_module(
    input        clk,
    input        clr,
    input  [3:0] A,
    input  [3:0] B,
    input        sub,
    output [3:0] Y
);reg [3:0] obf_temp;

    always @(posedge clk)
        if (clr) obf_temp <= 4'b0;
        else if (sub) obf_temp <= A - B;
        else obf_temp <= A + B;

    assign Y = obf_temp;

endmodule
